--
-- Triggers `prenotazione`
--
DELIMITER $$
CREATE TRIGGER `RV3` BEFORE INSERT ON `prenotazione` FOR EACH ROW BEGIN
    DECLARE Conteggio INT;
    DECLARE Limite INT;
    
    SELECT COUNT(*) INTO Conteggio FROM prenotazione WHERE IDTour = NEW.IDTour;
    SELECT VisitatoriMax INTO Limite FROM Tour WHERE ID = NEW.IDTour;
    
    IF Conteggio >= Limite THEN
        SIGNAL SQLSTATE '45000' SET MESSAGE_TEXT = 'Posti esauriti';
    END IF;
END
$$
DELIMITER ;

