--
-- Triggers `valutazione`
--
DELIMITER $$
CREATE TRIGGER `RV4` BEFORE INSERT ON `valutazione` FOR EACH ROW BEGIN
    DECLARE verifica INT;
    
    SELECT COUNT(*) INTO verifica
    FROM prenotazione
    JOIN tour ON prenotazione.IDTour = tour.ID
    WHERE prenotazione.IDVisitatore = NEW.IDVisitatore 
      AND tour.Licenza = NEW.Licenza;
    
    IF verifica = 0 THEN
        SIGNAL SQLSTATE '45000' 
        SET MESSAGE_TEXT = 'Solo i visitatori che hanno partecipato a tour con questa guida possono valutarla';
    END IF;
END
$$
DELIMITER ;

